import { FunctionReference } from 'convex/server';

/**
 * Hook: Get subscription status in real-time.
 * Updates automatically when webhook changes the status.
 *
 * ```tsx
 * const sub = useCreemSubscription(api.creem.getSubscriptionByCustomer, {
 *   creemCustomerId: "cust_xxx"
 * });
 * // sub updates in REAL TIME when webhook arrives
 * ```
 */
declare function useCreemSubscription(queryRef: FunctionReference<"query">, args: Record<string, unknown>): any;
/**
 * Hook: Check if user has active access.
 * Real-time boolean check.
 *
 * ```tsx
 * const { hasAccess, status } = useCreemAccess(api.creem.hasActiveSubscription, {
 *   creemCustomerId: "cust_xxx"
 * });
 * ```
 */
declare function useCreemAccess(queryRef: FunctionReference<"query">, args: Record<string, unknown>): any;
/**
 * Hook: Create a checkout session and redirect.
 *
 * ```tsx
 * const { startCheckout, isLoading } = useCreemCheckout(api.creem.createCheckout);
 *
 * <button onClick={() => startCheckout({
 *   productId: "prod_xxx",
 *   successUrl: "/success"
 * })}>
 *   Buy Now
 * </button>
 * ```
 */
declare function useCreemCheckout(actionRef: FunctionReference<"action">): {
    startCheckout: (args: {
        productId: string;
        successUrl: string;
        metadata?: Record<string, unknown>;
        customerEmail?: string;
    }) => Promise<any>;
    isLoading: boolean;
    error: string;
};
/**
 * Hook: List payments in real-time.
 *
 * ```tsx
 * const payments = useCreemPayments(api.creem.getPaymentsByCustomer, {
 *   creemCustomerId: "cust_xxx"
 * });
 * ```
 */
declare function useCreemPayments(queryRef: FunctionReference<"query">, args: Record<string, unknown>): any;

export { useCreemAccess, useCreemCheckout, useCreemPayments, useCreemSubscription };
